const TOKEN = '8732835567:AAH6ZqWNPM57nuSY6SybjtlVjJk_vxBcOjk';
const BASE = `https://api.telegram.org/bot${TOKEN}`;
const PROXY = 'https://kokolsk1y.app.n8n.cloud/webhook/tv-video?url=';

function proxyUrl(url) {
  return url ? PROXY + encodeURIComponent(url) : '';
}

async function tgGet(url) {
  return await this.helpers.request({ method: 'GET', url, json: true });
}

// Кэш постов между запросами
const cache = $getWorkflowStaticData('global');
if (!cache.photos) cache.photos = [];
if (!cache.video) cache.video = null;

const updates = $input.first().json.result || [];

// Берём только channel_post, сортируем по message_id (старые → новые)
const channelPosts = updates
  .filter(u => u.channel_post)
  .map(u => u.channel_post)
  .sort((a, b) => a.message_id - b.message_id);

const groupMap = {};
for (const msg of channelPosts) {
  if (msg.photo) {
    const largest = msg.photo[msg.photo.length - 1];
    const fileJson = await this.helpers.request({ method: 'GET', url: `${BASE}/getFile?file_id=${largest.file_id}`, json: true });
    const imgUrl = fileJson.ok
      ? `https://api.telegram.org/file/bot${TOKEN}/${fileJson.result.file_path}`
      : '';
    const gid = msg.media_group_id || ('single_' + msg.message_id);
    if (!groupMap[gid]) {
      groupMap[gid] = { type: 'photo', text: '', date: new Date(msg.date * 1000).toISOString(), imgs: [], msg_id: msg.message_id };
    }
    groupMap[gid].imgs.push(proxyUrl(imgUrl));
    if (msg.caption) groupMap[gid].text = msg.caption;
  }

  if (msg.video) {
    // getFile работает только до 20MB — для больших файлов пропускаем
    let videoUrl = '';
    const MAX_SIZE = 20 * 1024 * 1024;
    if (!msg.video.file_size || msg.video.file_size <= MAX_SIZE) {
      try {
        const videoJson = await this.helpers.request({ method: 'GET', url: `${BASE}/getFile?file_id=${msg.video.file_id}`, json: true });
        if (videoJson.ok) videoUrl = `https://api.telegram.org/file/bot${TOKEN}/${videoJson.result.file_path}`;
      } catch(e) { /* файл слишком большой */ }
    }

    let thumbUrl = '';
    const thumb = msg.video.thumbnail || msg.video.thumb;
    if (thumb) {
      try {
        const thumbJson = await this.helpers.request({ method: 'GET', url: `${BASE}/getFile?file_id=${thumb.file_id}`, json: true });
        if (thumbJson.ok) thumbUrl = `https://api.telegram.org/file/bot${TOKEN}/${thumbJson.result.file_path}`;
      } catch(e) {}
    }

    cache.video = {
      type: 'video',
      text: msg.caption || '',
      date: new Date(msg.date * 1000).toISOString(),
      videoUrl: proxyUrl(videoUrl),
      videoThumb: proxyUrl(thumbUrl),
      msg_id: msg.message_id
    };
  }
}

// Добавляем сгруппированные фото в кэш
const newGroups = Object.values(groupMap).sort((a, b) => a.msg_id - b.msg_id);
for (const group of newGroups) {
  cache.photos.unshift(group);
}
cache.photos = cache.photos.slice(0, 2);

// Подтверждаем обновления
if (updates.length > 0) {
  const lastId = Math.max(...updates.map(u => u.update_id));
  await this.helpers.request({ method: 'GET', url: `${BASE}/getUpdates?offset=${lastId + 1}&limit=1`, json: true });
}

// YouTube RSS — последний Shorts
if (!cache.youtube) cache.youtube = null;
try {
  const xmlText = await this.helpers.request({ method: 'GET', url: 'https://www.youtube.com/feeds/videos.xml?channel_id=UCza1f89Llt4sTN0QoFfeUxA', json: false });
  const idMatch = xmlText.match(/<yt:videoId>([^<]+)<\/yt:videoId>/);
  const titleMatches = [...xmlText.matchAll(/<title>([^<]+)<\/title>/g)];
  const pubMatch = xmlText.match(/<published>([^<]+)<\/published>/);
  const descMatch = xmlText.match(/<media:description>([\s\S]*?)<\/media:description>/);
  if (idMatch) {
    const embedId = idMatch[1];
    const title = titleMatches[1] ? titleMatches[1][1] : '';
    const desc = descMatch ? descMatch[1].trim() : '';
    const date = pubMatch ? pubMatch[1] : new Date().toISOString();
    cache.youtube = { type: 'youtube', embedId, title, text: title + (desc ? '\n\n' + desc : ''), date };
  }
} catch(e) { /* YouTube RSS недоступен */ }

const posts = [
  ...cache.photos,
  ...(cache.video ? [cache.video] : []),
  ...(cache.youtube ? [cache.youtube] : [])
];

return [{ json: { posts, updatedAt: new Date().toISOString() } }];
